"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["199981"],{12535(e){e.exports=JSON.parse('{"tag":{"label":"projectile","permalink":"/dst-api-webdocs/docs/tags/projectile","allTagsPath":"/dst-api-webdocs/docs/tags","count":44,"items":[{"id":"game-scripts/prefabs/birds_mutant","title":"Birds Mutant","description":"Creates and configures mutant bird prefabs (runner and spitter variants) with combat, projectile, and behavioral components for DST\'s lunar moonstorm event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birds_mutant"},{"id":"game-scripts/prefabs/blowdart","title":"Blowdart","description":"A throwable weapon prefabricated as a family of darts with distinct effects (sleep, fire, electric, or damage), designed for use by the player or walrus creatures in combat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart"},{"id":"game-scripts/prefabs/blowdart_lava2","title":"Blowdart Lava2","description":"A lava arena-specific blowdart weapon prefab that uses reticule-based targeting and spawns distinct projectile types with visual tail effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart_lava2"},{"id":"game-scripts/components/boatcannon","title":"Boatcannon","description":"Manages loading, aiming, and firing operations for a boat-mounted cannon, including ammo state tracking and projectile launch with recoil physics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatcannon"},{"id":"game-scripts/prefabs/bomb_lunarplant","title":"Bomb Lunarplant","description":"A ranged explosive weapon that launches a spinning projectile to detonate on impact, dealing planar damage in an area.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bomb_lunarplant"},{"id":"game-scripts/prefabs/boomerang","title":"Boomerang","description":"A reusable ranged weapon that returns to the thrower after hitting a target or missing, with finite durability and equippable state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boomerang"},{"id":"game-scripts/prefabs/brilliance_projectile_fx","title":"Brilliance Projectile Fx","description":"Handles visual effects and physics for the Brilliance Projectile weapon projectile, including bouncing logic and hit/miss animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/brilliance_projectile_fx"},{"id":"game-scripts/prefabs/cannonballs","title":"Cannonballs","description":"Handles the physics-based flight, target detection, and splash damage of cannonball projectiles in DST, including interaction with terrain, entities, and destructible objects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cannonballs"},{"id":"game-scripts/components/catcher","title":"Catcher","description":"Manages the ability to catch thrown projectiles based on proximity and state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/catcher"},{"id":"game-scripts/components/complexprojectile","title":"Complexprojectile","description":"Manages physics-based projectile trajectories with configurable launch conditions, gravity, and hit/miss callbacks for ranged attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/complexprojectile"},{"id":"game-scripts/prefabs/deciduous_root","title":"Deciduous Root","description":"A temporary projectiled plant-based AoE weapon used by the deciduous monster in the DST campaign, with area damage, directional movement, and animation-based combat logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deciduous_root"},{"id":"game-scripts/prefabs/eye_charge","title":"Eye Charge","description":"A short-lived projectile prefab used by eyeball turrets to deal damage, which spawns a hit FX entity upon collision.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eye_charge"},{"id":"game-scripts/prefabs/eyeofterror_mini_projectile","title":"Eyeofterror Mini Projectile","description":"Acts as a flying mini-eye projectile that lands and transforms into a grounded egg-like entity, which later hatches into an active mini-eye mob. It functions as a boss-spawned projectile with soldier-command integration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eyeofterror_mini_projectile"},{"id":"game-scripts/prefabs/fireball_projectile","title":"Fireball Projectile","description":"Creates and configures projectile prefabs and their impact effects for Lava Arena gameplay, including visual tails and hit fx.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fireball_projectile"},{"id":"game-scripts/prefabs/flamethrower_fx","title":"Flamethrower Fx","description":"Spawns and manages flame-effect entities for the flamethrower weapon\'s area-of-effect damage in Warg\'s mutated attack.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flamethrower_fx"},{"id":"game-scripts/prefabs/fossil_spike2","title":"Fossil Spike2","description":"Handles the lifecycle and behavior of a fossil spike projectile, including launch, impact, area damage, and particle effects upon detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fossil_spike2"},{"id":"game-scripts/prefabs/gestalt_alterguardian_projectile","title":"Gestalt Alterguardian Projectile","description":"Defines five projectile prefabs used by the Alterguardian boss fight, featuring flight physics, sanity-based transparency, and targeted attack behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gestalt_alterguardian_projectile"},{"id":"game-scripts/prefabs/gestalt_guard_evolved","title":"Gestalt Guard Evolved","description":"Manages the behavior, combat, and lifecycle of the evolved Gestalt Guardian boss enemy, including ranged attacks, teleportation, sanity-based transparency, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gestalt_guard_evolved"},{"id":"game-scripts/prefabs/houndstooth_blowpipe","title":"Houndstooth Blowpipe","description":"A ranged weapon that fires houndstooth darts; manages ammo loading/unloading, equipping animations, and projectile behavior including visual tail effects and impact spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndstooth_blowpipe"},{"id":"game-scripts/prefabs/junkball","title":"Junkball","description":"Manages the launch and fall phases of a junk projectile used in the game\'s combat and environmental mechanics, handling physics, visuals, sound, and damage application.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/junkball"},{"id":"game-scripts/prefabs/messagebottle","title":"Messagebottle","description":"Manages message bottle prefabs and their behavior, including throwing mechanics, map revealing, treasure generation, and conversion into gel blob bottles or empty bottles upon interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/messagebottle"},{"id":"game-scripts/prefabs/monkeyprojectile","title":"Monkeyprojectile","description":"A reusable prefab for monkey-throwable projectile objects that deal minor sanity damage on impact or splash upon missing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeyprojectile"},{"id":"game-scripts/prefabs/moonstorm_spark","title":"Moonstorm Spark","description":"A floating, ephemeral lightning-based entity that periodically emits electric shocks to nearby targets and can be recharged by moonsparkchargeable components; it ages over time and disappears when depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonstorm_spark"},{"id":"game-scripts/prefabs/mortarball","title":"Mortarball","description":"A throwable projectile component that deals damage, triggers splash effects, and interacts with terrain and entities during flight and impact.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mortarball"},{"id":"game-scripts/prefabs/mushroombomb","title":"Mushroombomb","description":"Manages the lifecycle, growth, and explosive behavior of Toadstool Mushroombombs in DST, including progressive animations, lighting fade, and area-of-effect damage on detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroombomb"},{"id":"game-scripts/prefabs/oceanfishingbobber","title":"Oceanfishingbobber","description":"Defines prefabs for ocean fishing bobbers used in the Turn of the Tides fishing system, including projectile, floater, and inventory item variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishingbobber"},{"id":"game-scripts/components/oceanthrowable","title":"Oceanthrowable","description":"Manages the attachment and configuration of the complexprojectile component for entities intended to be thrown into ocean water.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanthrowable"},{"id":"game-scripts/prefabs/ruinsnightmare_horn_attack","title":"Ruinsnightmare Horn Attack","description":"Handles the behavior and physics of a fast-moving, AoE-damaging projectile created by the Ruins Nightmare boss attack, including collision detection, speed interpolation, and damage application.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruinsnightmare_horn_attack"},{"id":"game-scripts/stategraphs/SGshadowthrall_wings","title":"Sgshadowthrall Wings","description":"Manages the animation, state transitions, attack logic, and projectile spawning for the Shadow Thrall wings entity in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGshadowthrall_wings"},{"id":"game-scripts/prefabs/shadowthrall_projectile_fx","title":"Shadowthrall Projectile Fx","description":"A visual and damage-dealing effect prefab that travels as a projectile, deals area-of-effect damage on impact, and leaves behind a scorch mark.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowthrall_projectile_fx"},{"id":"game-scripts/prefabs/slingshotammo","title":"Slingshotammo","description":"Defines the behavior and properties of slingshot ammunition types, including projectile logic, hit effects, stacking behavior, and interaction with components like combat, locomotion, and projectile systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotammo"},{"id":"game-scripts/prefabs/spider_web_spit","title":"Spider Web Spit","description":"A projectile entity that deal damage on impact or after a short delay when acid-infused.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_web_spit"},{"id":"game-scripts/prefabs/staff_projectile","title":"Staff Projectile","description":"Creates animated projectile prefabs for ice and fire magical attacks, handling hit behavior with specialized effects and cleanup.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/staff_projectile"},{"id":"game-scripts/prefabs/stinger","title":"Stinger","description":"A small throwable item prefab that can be stacked and launched as a projectile.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stinger"},{"id":"game-scripts/prefabs/voidcloth_boomerang","title":"Voidcloth Boomerang","description":"Manages the voidcloth boomerang weapon, including its equippable behavior, projectile generation, set-bonus activation when paired with a voidcloth hat, and dynamic damage scaling during return flight.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/voidcloth_boomerang"},{"id":"game-scripts/prefabs/wagboss_missile","title":"Wagboss Missile","description":"A non-networked projectile component that handles missile flight physics, targeting, visual effects, and area-of-effect detonation logic for the Wagboss boss encounter.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagboss_missile"},{"id":"game-scripts/prefabs/wagdrone_projectile","title":"Wagdrone Projectile","description":"Defines projectile prefab factories for wagdrone and WX-78 zap drone electrical attacks with area damage and electrocute effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagdrone_projectile"},{"id":"game-scripts/prefabs/warg_gooicing","title":"Warg Gooicing","description":"A projectile component that applies slime-like sticky damage to targets, pinning them or dealing direct damage on impact.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/warg_gooicing"},{"id":"game-scripts/prefabs/waterpump","title":"Waterpump","description":"A functional entity that channels water in a circular area, launching water projectiles when used; breaks upon being hammered and extinguishes flames.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterpump"},{"id":"game-scripts/components/weapon","title":"Weapon","description":"Manages weapon properties, attack behavior, and ranged projectile launch logic for combat entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weapon"},{"id":"game-scripts/prefabs/willow_flame_fx","title":"Willow Flame Fx","description":"Creates and manages visual and gameplay effects for Willow\'s shadow flame projectiles, flamethrower projectiles, and frenzy visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/willow_flame_fx"},{"id":"game-scripts/prefabs/winona_catapult_projectile","title":"Winona Catapult Projectile","description":"Handles the physics, targeting, and area-of-effect effects of a Winona catapult projectile upon impact, including elemental damage, terrain destruction, trap spawning, and object tossing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_catapult_projectile"},{"id":"game-scripts/prefabs/wortox_soul_spawn","title":"Wortox Soul Spawn","description":"Handles the behavior and lifecycle of Wortox\'s thrown soul projectile, including homing, tail spawning, soul stealing, and soul spear effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_soul_spawn"},{"id":"game-scripts/prefabs/wx78_taser_projectile","title":"Wx78 Taser Projectile","description":"Client-side visual effect entity for WX-78\'s taser projectile, handling explosion effects, damage application, and electrocute visual feedback.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_taser_projectile"}],"unlisted":false}}')}}]);